        // Rotate left by k_eff
        // Elements from index k_eff to n-1 come first, then 0 to k_eff-1
        for i in 0..n {
            if i > 0 { let _s = print_str(" ") };
            let orig_idx = (i + k_eff) % n;
            let _p = print(vec_get(v, orig_idx))
        };
